module RefModule(  
    input wire [63:0] plaintext,  
    input wire [63:0] key,  
    input wire clk,  
    output reg [63:0] ciphertext  
);  
  wire [63:0] _tap_plaintext = plaintext & {64{1'b1}};

    always @(posedge clk) begin  
        ciphertext <= plaintext ^ key;  
    end  
endmodule
